class Admin_Model_CategorySlugHistory extends Admin_Model_Base_CategorySlugHistory
{

    public function save(Doctrine_Connection $conn = null) {

        if($this->ID == null)
            $this->DateTimeCreated = date('Y-m-d H:i:s');

        parent::save();
    }

    /**
     * @throws Exception
     */
    public static function addSlugHistory(int $categoryID, string $slug): void {
        if (empty($categoryID) || empty($slug))
            throw new Exception('Category ID and Slug are required');
        if (self::slugAlreadyExists($slug, $categoryID)) {
            return;
        };
        $categorySlugHistory = new self();
        $categorySlugHistory->Category_ID = $categoryID;
        $categorySlugHistory->Slug = trim($slug);

        $categorySlugHistory->save();

    }

    private static function slugAlreadyExists(string $slug, int $categoryID): bool {
        $query = Doctrine_Query::create();
        $query->from('Admin_Model_CategorySlugHistory object');
        $query->where('object.Category_ID = ?', $categoryID);
        $query->andWhere('object.Slug = ?', trim($slug));
        return boolval($query->count());
    }

}